long long solve(std::string s) {
    int n = s.length();
    std::vector<int> L, C, T;

    // Precompute positions of 'L', 'C', 'T'
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'L') L.push_back(i);
        else if (s[i] == 'C') C.push_back(i);
        else if (s[i] == 'T') T.push_back(i);
    }

    // Function to count number of "LCT" subsequences with given L, C, T indices
    auto count = [](const std::vector<int>& L, const std::vector<int>& C, const std::vector<int>& T) {
        int count = 0;
        for (int i = 0; i < C.size(); ++i) {
            int c = C[i];
            // Count number of L's before C[i]
            int l = std::lower_bound(L.begin(), L.end(), c) - L.begin();
            // Count number of T's after C[i]
            int t = std::upper_bound(T.begin(), T.end(), c) - T.begin();
            count += l * t;
        }
        return count;
    };

    // Original count without insertion
    long long original = count(L, C, T);

    // Try inserting 'L' at each position
    long long max_count = original;
    for (int i = 0; i <= n; ++i) {
        // Insert 'L' at position i
        std::vector<int> new_L = L;
        if (i < L[0]) new_L.insert(new_L.begin(), i);
        else new_L.insert(new_L.begin() + std::lower_bound(L.begin(), L.end(), i) - L.begin(), i);

        long long new_count = count(new_L, C, T);
        max_count = std::max(max_count, new_count);
    }

    // Try inserting 'C' at each position
    for (int i = 0; i <= n; ++i) {
        std::vector<int> new_C = C;
        if (i < C[0]) new_C.insert(new_C.begin(), i);
        else new_C.insert(new_C.begin() + std::lower_bound(C.begin(), C.end(), i) - C.begin(), i);

        long long new_count = count(L, new_C, T);
        max_count = std::max(max_count, new_count);
    }

    // Try inserting 'T' at each position
    for (int i = 0; i <= n; ++i) {
        std::vector<int> new_T = T;
        if (i < T[0]) new_T.insert(new_T.begin(), i);
        else new_T.insert(new_T.begin() + std::lower_bound(T.begin(), T.end(), i) - T.begin(), i);

        long long new_count = count(L, C, new_T);
        max_count = std::max(max_count, new_count);
    }

    return max_count;
}
